typedef struct {
 int *data;
 int size;
 int capacity;
} DynamicArray;

void init(DynamicArray *arr) {
 arr->capacity = 4;
 arr->data = malloc(arr->capacity * sizeof(int));
 arr->size = 0;
}

void push_back(DynamicArray *arr, int val) {
 if(arr->size == arr->capacity) {
 arr->capacity *= 2;
 arr->data = realloc(arr->data, arr->capacity * sizeof(int));
 }
 arr->data[arr->size++] = val;
}

int pop_back(DynamicArray *arr) {
 if(arr->size == 0) return -1;
 return arr->data[--arr->size];
}

int get(DynamicArray *arr, int i) {
 if(i < 0 || i >= arr->size) return -1;
 return arr->data[i];
}

void insert(DynamicArray *arr, int index, int value) {
 if(index < 0 || index > arr->size) return;

 if(arr->size == arr->capacity) {
 arr->capacity *= 2;
 arr->data = realloc(arr->data, arr->capacity * sizeof(int));
 }

 // Shift elements right
 for(int i = arr->size; i > index; i--) {
 arr->data[i] = arr->data[i - 1];
 }

 arr->data[index] = value;
 arr->size++;
}
// Time: O(n), Space: O(1)

void delete(DynamicArray *arr, int index) {
 if(index < 0 || index >= arr->size) return;

 // Shift elements left
 for(int i = index; i < arr->size - 1; i++) {
 arr->data[i] = arr->data[i + 1];
 }

 arr->size--;
 if(arr->size < arr->capacity / 4) {
 arr->capacity /= 2;
 arr->data = realloc(arr->data, arr->capacity * sizeof(int));
 }
}
// Time: O(n), Space: O(1)
